INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Double-entry accounting$q$, $q$Full double-entry bookkeeping engine with journal entries, ledgers, and automatic balancing for accurate financial records.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Offline-first desktop app$q$, $q$Runs entirely on Windows, macOS, or Linux with data stored locally in SQLite, requiring no internet connection or account signup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Invoicing and billing$q$, $q$Customizable sales and purchase invoice templates with support for recurring invoices and payment tracking against open balances.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Point of Sale$q$, $q$A built-in POS mode for recording retail-style, in-person transactions directly against inventory and accounts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Multi-currency support$q$, $q$Invoice and transact in multiple currencies with automatic exchange-rate conversion for reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Financial reports$q$, $q$Generates Profit and Loss, Balance Sheet, Trial Balance, and General Ledger reports out of the box.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$GST and tax support$q$, $q$Includes India-specific GST compliance fields and tax templates alongside general tax configuration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Data ownership and portability$q$, $q$All data lives in a local file the user controls, which can be backed up, moved, or exported without vendor lock-in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Completely free with no subscription, seat limits, or feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Works fully offline, which suits users who want privacy and independence from cloud outages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Clean, modern interface built with Vue.js, unusual for free accounting software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Open-source codebase on GitHub that can be audited, self-hosted, or extended by developers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Data stored locally, giving users full ownership and easy backup or migration$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$No native multi-user or team collaboration support within the desktop app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$No built-in payroll or advanced ERP modules found in sibling product ERPNext$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$No official mobile app for on-the-go invoicing or bookkeeping$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Relies on community and GitHub-based support rather than dedicated customer service$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Local-only data storage means users are responsible for their own backups and device security$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Is Frappe Books really free?$q$, $q$Yes. Frappe Books is fully open-source and free to download and use, with no subscription fees, seat limits, or locked features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Does Frappe Books work offline?$q$, $q$Yes. It is an offline-first desktop application that stores all data locally in a SQLite database file, so an internet connection is not required to use it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$What platforms does Frappe Books support?$q$, $q$Frappe Books is available as a desktop application for Windows, macOS, and Linux, built using Electron.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Is Frappe Books the same company as ERPNext?$q$, $q$Yes. Both are built and maintained by Frappe Technologies, the Mumbai-based open-source software company founded by Rushabh Mehta.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Can multiple people use Frappe Books at once?$q$, $q$Frappe Books is designed as a single-user, single-device desktop application and does not include built-in real-time multi-user collaboration; businesses needing that typically use ERPNext instead.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Does Frappe Books support GST or other regional taxes?$q$, $q$Yes, it includes India-specific GST support along with general multi-currency and tax configuration options for other regions.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Freelancer invoicing and bookkeeping$q$, $q$Solo consultants and freelancers use Frappe Books to send invoices, track payments, and generate profit and loss statements without paying for cloud accounting software.$q$, $q$Freelancers and independent consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Small retail bookkeeping$q$, $q$Small shop owners use the built-in Point of Sale module alongside double-entry accounting to manage day-to-day sales and inventory-linked transactions.$q$, $q$Small retail and local businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Privacy-focused offline accounting$q$, $q$Businesses that prefer to keep financial records off third-party servers use Frappe Books for fully local, self-managed bookkeeping.$q$, $q$Privacy-conscious small business owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$Free (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full double-entry accounting","Unlimited invoices and journal entries","Point of Sale module","Multi-currency support","All standard financial reports","Local data storage with no account required"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Frappe Books is a free, open-source, offline-first desktop accounting application built by Frappe Technologies, the Mumbai-based company behind ERPNext and Frappe HR. It publicly launched in May 2020 and targets freelancers and small businesses that want full double-entry bookkeeping without a monthly subscription.$q$, $q$The application runs entirely on the user's computer using Electron and stores data locally in a SQLite file, meaning it works fully offline and gives users complete ownership of their financial data instead of storing it on a vendor's servers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include customer and vendor invoicing, double-entry journal entries, bank reconciliation, multi-currency support, and a Point of Sale module for retail transactions.$q$, $q$Financial reporting covers Profit and Loss statements, Balance Sheet, Trial Balance, and General Ledger, alongside a dashboard that summarizes cash flow, receivables, and profitability at a glance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Frappe Books has no paid tiers. The entire desktop application, including every accounting and reporting feature, is free under an open-source license with no seat limits, ads, or feature gates.$q$, $q$There is no official hosted or cloud version of Frappe Books itself; businesses that need multi-user or cloud access typically move to ERPNext, which is a separate paid-hosting product from the same company.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('99b0c7e3-3443-428c-9117-bae2653976d1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Employee lifecycle management$q$, $q$Handles onboarding, promotions, transfers, and exit interviews with documented feedback in a single employee record.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Leave and attendance$q$, $q$Configurable leave policies, regional holiday calendars, and geolocation-based check-in and check-out with attendance reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Payroll and taxation$q$, $q$Salary structure configuration, automated payroll runs, tax computation, and payslip generation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Recruitment and applicant tracking$q$, $q$Manage job openings, candidate pipelines, and interview scheduling within the same system as onboarding.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Performance management$q$, $q$Set goals, run appraisal cycles, and track employee performance history over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Expense claims and asset management$q$, $q$Employees submit expense claims and track company assets assigned to them, with approval workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$No-code customization$q$, $q$Create custom fields, forms, and multi-level approval workflows without writing code, using the Frappe Framework's DocType system.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Third-party integrations$q$, $q$Connects with biometric attendance devices and accounting software, including native integration with ERPNext.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Fully open source under AGPL-3.0, with no per-employee license fees for self-hosted deployments$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Deep, full-featured module set spanning payroll, recruitment, performance, and attendance rather than a narrow HR tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Highly customizable without code through the Frappe Framework's built-in workflow and form builder$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Frappe Cloud hosting pricing is based on infrastructure rather than per-user seats, which can be cheaper at scale$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Backed by a large open-source community and network of 200-plus certified implementation partners$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Self-hosting requires ongoing server management, security, and backup responsibility$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Steeper learning curve than narrowly focused commercial HR SaaS tools like Gusto or BambooHR$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Smaller third-party integration marketplace compared to large commercial HRIS platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Advanced support (beyond community forums) typically requires paying for Frappe Cloud or a certified partner$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Payroll tax rules for markets outside India may need additional configuration or a partner's help$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Is Frappe HR free to use?$q$, $q$The core software is free and open source under AGPL-3.0 and can be self-hosted at no license cost, though organizations still pay for server infrastructure or can opt into paid Frappe Cloud hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$How much does Frappe Cloud hosting for Frappe HR cost?$q$, $q$Frappe Cloud pricing starts around $5 per month for a shared Sites plan, around $20 per month for a dedicated Servers plan, and around $125 per month for Premium Servers, with custom Enterprise pricing for larger deployments.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Is Frappe HR the same as ERPNext's HR module?$q$, $q$Frappe HR originated as ERPNext's HR module and was spun out into its own standalone, independently branded product in 2022, though it still shares the same Frappe Framework architecture.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Does Frappe HR handle payroll?$q$, $q$Yes, it includes salary structure configuration, automated payroll runs, tax computation, and payslip generation as core modules.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Can Frappe HR be customized without coding?$q$, $q$Yes, the underlying Frappe Framework provides a no-code system for building custom fields, forms, and multi-level approval workflows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Who maintains Frappe HR?$q$, $q$It is developed and maintained by Frappe Technologies, an open-source software company headquartered in Mumbai, India, founded by Rushabh Mehta.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$End-to-end payroll and compliance$q$, $q$Mid-sized companies use Frappe HR to run payroll, compute taxes, and generate payslips without paying per-employee SaaS fees.$q$, $q$Small and mid-sized business HR teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Custom HR workflows for regulated industries$q$, $q$Organizations with unique approval chains or compliance requirements use the no-code workflow builder to model processes that off-the-shelf HR SaaS tools cannot easily support.$q$, $q$Organizations with complex or regional HR compliance needs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Unified ERP and HR data$q$, $q$Businesses already running ERPNext adopt Frappe HR to keep employee, payroll, and financial data inside a single connected ecosystem.$q$, $q$Existing Frappe or ERPNext customers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full HRMS source code under AGPL-3.0","Unlimited employees, no per-seat fees","All HR, payroll, and recruitment modules","Self-managed infrastructure and updates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Frappe Cloud - Sites$q$, $q$From $5/month$q$, $q$Monthly, usage-based$q$, NULL, $q$["Shared server infrastructure","Managed upgrades and backups","Lowest-cost managed entry point","Pay for infrastructure, not per user"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Frappe Cloud - Servers$q$, $q$From $20/month$q$, $q$Monthly, usage-based$q$, NULL, $q$["Dedicated virtual machine for multiple sites","Better price-performance for growing teams","Managed backups and monitoring"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Frappe Cloud - Premium Servers$q$, $q$From $125/month$q$, $q$Monthly, usage-based$q$, NULL, $q$["Enhanced isolation and performance","Advanced infrastructure features","Suited to larger, higher-traffic deployments"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["Custom infrastructure and SLAs","Dedicated support","Volume implementation assistance"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Frappe HR is an open-source human resources and payroll platform built on the Frappe Framework by Frappe Technologies. It was spun out of ERPNext's HR module into a standalone product in 2022, giving it dedicated branding and release cycles while sharing the same underlying architecture.$q$, $q$It covers more than a dozen HR functions including employee lifecycle management, leave and attendance, payroll and taxation, recruitment, performance management, and training, and can be self-hosted for free or run on managed Frappe Cloud hosting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core modules include employee onboarding and exit management, configurable leave policies with regional holiday calendars, geolocation-based attendance tracking, payroll runs with tax computation, recruitment and applicant tracking, and performance management.$q$, $q$No-code customization lets administrators build custom fields, forms, and multi-level approval workflows without writing code, and the platform integrates with biometric devices and accounting software.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core software is free and open source under AGPL-3.0, and can be self-hosted at the cost of server infrastructure, typically around $40 per month for a basic VPS plus backup and security costs.$q$, $q$Managed Frappe Cloud hosting starts around $5 per month for a shared Sites plan, $20 per month for dedicated Servers, and $125 per month for Premium Servers, with pricing based on infrastructure usage rather than per-employee seat fees.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2e1130d-9c44-4370-a41a-c2cdb9ce88e0', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$SERP and competitor research$q$, $q$Analyzes the top-ranking pages for a target keyword to surface common topics, headings, and questions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$AI-generated content briefs$q$, $q$Turns SERP research into structured briefs with recommended word counts, topics, and questions to cover.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$AI writing assistant$q$, $q$Drafts full articles, outlines, FAQs, and meta descriptions grounded in the content brief.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content Guard monitoring$q$, $q$Tracks published pages for ranking or traffic drops and flags content that needs refreshing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Site audits$q$, $q$Scans site pages for technical and on-page SEO issues at scale.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$GEO visibility tracking$q$, $q$Monitors whether and how a brand's content is cited or represented in AI chatbot answers such as ChatGPT and AI Overviews.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content calendar and internal linking$q$, $q$Plans publishing schedules and surfaces internal linking opportunities across a site.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Auto-publishing Agent$q$, $q$Automatically generates and publishes certain content types, such as FAQ and glossary pages, directly to a connected CMS.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Combines keyword research, briefing, writing, auditing, and GEO tracking in a single subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$SERP-grounded briefs give writers concrete, data-backed guidance instead of generic AI prompts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content Guard helps teams find and refresh underperforming content instead of only publishing new pages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Actively adding generative-engine optimization features as AI search answers grow in importance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Overage-based pricing lets teams exceed quotas occasionally without forcing a full tier upgrade$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Monthly article and seat quotas can feel restrictive for larger content teams on lower tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Pricing gap between monthly and annual billing is steep, pushing users toward annual commitments$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Extra seats and overages add up quickly for agencies managing many clients or writers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$AI-generated drafts still require human editing for accuracy, voice, and factual verification$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Enterprise-level features like SSO and white-labeling are gated behind custom, undisclosed pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$How much does Frase cost?$q$, $q$Frase starts at $39 per month for the Starter plan when billed annually ($49 per month billed monthly), with Professional at $103 per month annually and Scale at $239 per month annually. Enterprise pricing is custom.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Does Frase offer a free trial?$q$, $q$Yes, Frase offers a 7-day free trial with Professional-level features and no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Who owns Frase?$q$, $q$Frase was founded in 2017 by Tomas Ratia and was acquired by Copysmith AI in October 2022, which continues to operate it as an independently branded product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$What is GEO tracking in Frase?$q$, $q$GEO (generative-engine optimization) tracking monitors whether and how a brand's content is cited or represented in AI-generated search answers from tools like ChatGPT and Google AI Overviews.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$What happens if I exceed my monthly article limit?$q$, $q$On Professional and Scale plans, teams can pay per-article, per-audit-page, and per-AI-prompt overage rates instead of being forced to upgrade to a higher tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$How is Frase different from Surfer SEO?$q$, $q$Both tools offer SERP-based content briefs and optimization scoring, but Frase bundles a wider workflow including AI writing, technical site audits, Content Guard monitoring, and GEO visibility tracking into its plans.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$SEO content briefs at scale$q$, $q$Content teams use Frase to generate SERP-informed briefs for writers, ensuring articles cover the topics and questions that ranking competitors already address.$q$, $q$In-house content marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Agency content production$q$, $q$Agencies managing SEO content for multiple clients use Frase's multi-site and multi-seat plans to research, brief, and audit content across accounts from one platform.$q$, $q$SEO and content marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Content refresh and decay monitoring$q$, $q$Teams use Content Guard to identify published pages that are losing rankings or traffic and prioritize which articles to update first.$q$, $q$SEO managers and content strategists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Starter$q$, $q$$39/month (annual) or $49/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["1 seat, 1 site","10 articles and 50 audit pages per month","25 AI generations, 20 diagrams","Content Guard monitoring for 3 pages","CMS publishing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Professional$q$, $q$$103/month (annual) or $129/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["3 seats, 5 sites (extra seats $29/month)","40 articles and 250 audit pages per month","100 AI generations, 50 diagrams","Content calendar and internal linking","Content Guard monitoring for 15 pages","Agent auto-publishes FAQ, glossary, and how-to content"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Scale$q$, $q$$239/month (annual) or $299/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["5 seats, up to 10 domains (extra seats $29/month)","100 articles and 1,000 audit pages per month","350 AI generations, custom diagrams","Content Guard monitoring for 50 pages","Full Agent auto-publishing across content types","Omni-channel content repurposing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["Custom seats and domains","White-label client portals and branded domains","SSO/SAML authentication","Dedicated account manager and SLA","Up to 24 months of historical data"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Frase is an AI-powered SEO content platform founded in 2017 by Tomas Ratia in Boston, Massachusetts. It was acquired by Copysmith AI in October 2022 and continues to operate as an independently branded, actively developed product.$q$, $q$The platform combines SERP research, AI-generated content briefs, an AI writing assistant, technical site audits, and generative-engine (GEO) visibility tracking to help teams plan, produce, and monitor SEO content in one workflow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Frase analyzes top-ranking pages for a target keyword to build content briefs with recommended topics, questions, and word counts, then lets writers or its AI assistant draft full articles grounded in that research.$q$, $q$Content Guard monitors published pages for ranking or traffic drops, a site audit tool flags technical SEO issues, and GEO tracking monitors whether a brand's content is cited in AI chatbot answers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plans are priced by monthly quotas of articles, audit pages, AI generations, and seats. Starter costs $39/month annually, Professional costs $103/month annually, and Scale costs $239/month annually, with an Enterprise tier available on request.$q$, $q$Extra seats cost $29/month on paid plans, and teams that exceed monthly quotas can pay per-article or per-audit-page overage fees instead of upgrading tiers. A 7-day free trial is available with no credit card required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab7b3699-804e-44f2-83c1-0814b44d388b', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Multi-portal scraping$q$, $q$Simultaneously searches ImmoScout24, Immowelt, Immonet, eBay Kleinanzeigen, and WG-Gesucht for new listings matching saved criteria.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Instant multi-channel notifications$q$, $q$Sends alerts through Slack, Telegram, Discord, email, or ntfy as soon as a new matching listing is found.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Duplicate detection$q$, $q$Stores seen listings in a local database so the same property is never reported more than once.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Bot-detection workarounds$q$, $q$Uses Puppeteer-based browser automation with fingerprint cloaking and, for some portals, reverse-engineered mobile APIs to reliably scrape sites with anti-bot protections.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Docker-based self-hosting$q$, $q$Distributed as a container image with mounted volumes for configuration and database, making it easy to run on home servers, NAS devices, or Unraid.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Configurable saved searches$q$, $q$Users define multiple search profiles with location, price, and property criteria across different portals.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$MCP server integration$q$, $q$Recent releases include a built-in Model Context Protocol server so AI assistants can query Fredy's listing and search data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Open-source and self-hosted$q$, $q$Fully open codebase under Apache-2.0 that users can audit, modify, and run entirely on their own infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Completely free with no subscription cost beyond the user's own hosting infrastructure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Aggregates multiple German real estate portals into a single unified alert stream$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Notifies faster than manually refreshing listing sites, which matters in competitive rental markets$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Open-source codebase can be audited, self-hosted, and extended by technically capable users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Supports popular self-hosted notification channels like ntfy and Discord alongside mainstream ones like email$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Requires Docker and basic self-hosting or command-line comfort to set up and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Scoped specifically to German real estate portals, with no support for other countries' listing sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Relies on web scraping, which can break when target portals change their site structure or anti-bot defenses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$No official commercial support, SLA, or customer service, since it is a volunteer-maintained project$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$No official hosted or managed version, so users must provide and maintain their own server$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Is Fredy free to use?$q$, $q$Yes, Fredy is fully open source and free under the Apache-2.0 license. The only cost is the infrastructure needed to self-host it, such as a home server or small VPS.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$What real estate portals does Fredy support?$q$, $q$Fredy scrapes ImmoScout24, Immowelt, Immonet, eBay Kleinanzeigen, and WG-Gesucht, all major German real estate listing platforms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$How do I install Fredy?$q$, $q$Fredy is distributed as a Docker container image and can be deployed with a simple docker run command, or installed as a community app on platforms like Unraid.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$What notification channels does Fredy support?$q$, $q$Fredy can send alerts via Slack, Telegram, Discord, email, or ntfy, a lightweight self-hosted push notification service.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Is Fredy only for real estate in Germany?$q$, $q$Yes, all of the platforms Fredy currently scrapes are German real estate portals, so it is primarily useful for people searching for housing in Germany.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Who maintains Fredy?$q$, $q$Fredy is maintained as an open-source project on GitHub under the orangecoding organization, without a dedicated company behind it.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Competitive apartment hunting$q$, $q$Renters searching in fast-moving markets like Berlin or Munich self-host Fredy to get instant alerts on new listings before they are gone.$q$, $q$Individual apartment and house hunters in Germany$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Multi-portal search consolidation$q$, $q$Users tired of checking several listing sites separately configure Fredy to aggregate searches across all major German portals into one notification stream.$q$, $q$Home buyers and renters comparing multiple portals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Home-lab and self-hosting projects$q$, $q$Self-hosting enthusiasts run Fredy alongside other Docker-based home automation tools on their NAS or home server as a practical, real-world use case.$q$, $q$Self-hosting and home-lab hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$Free (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under Apache-2.0","Unlimited saved searches and notifications","Docker-based self-hosted deployment","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Fredy ('Find Real Estate Damn Easy') is a free, open-source, self-hosted tool that continuously scrapes German real estate portals including ImmoScout24, Immowelt, Immonet, eBay Kleinanzeigen, and WG-Gesucht, and instantly notifies users of new matching listings.$q$, $q$It is maintained on GitHub under the orangecoding organization and licensed under Apache-2.0. It is not a commercial company but a community-maintained self-hosted project popular in home-lab and self-hosting circles.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Fredy runs scheduled scrapes across multiple German listing portals simultaneously, de-duplicates results in a local database, and pushes new matches via Slack, Telegram, Discord, email, or ntfy.$q$, $q$Built on Node.js and Puppeteer with bot-detection workarounds, it ships as a Docker container and, in newer releases, includes a built-in MCP server for AI assistant integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Fredy is completely free and open source, with no subscription tiers or paid features. The only cost is the infrastructure the user provides to run the Docker container, such as a home server, NAS, or small VPS.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2315b74d-957e-4a28-a863-32fc0da75242', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Unlimited free tier$q$, $q$The Free plan supports unlimited projects, tasks, storage, and users at no cost, unusual among project management tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Task and milestone management$q$, $q$Organize work with task lists, subtasks, dependencies, and project milestones with due dates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Built-in CRM and invoicing$q$, $q$The Business tier adds a CRM module and an 'Invoices+' feature so small businesses can manage client relationships and billing alongside projects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Issue tracker and wiki$q$, $q$Business and Enterprise tiers include a dedicated issue tracker and team wiki for documentation and bug tracking.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Free collaborator seats$q$, $q$External collaborators can be added to paid-plan projects without incurring per-user licensing costs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Cloud storage integrations$q$, $q$Pro and higher tiers connect with Google Drive, Dropbox, and OneDrive for file management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$White labeling and SSO$q$, $q$Enterprise plans support white-label branding and single sign-on via SAML for larger organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Mobile apps$q$, $q$Native iOS and Android apps let teams manage tasks and projects on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Free plan supports genuinely unlimited users, projects, and tasks, not just a trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Very low per-user cost on paid tiers compared to most project management competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$External collaborators remain free even on paid plans, useful for client-facing agencies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Business tier bundles a CRM and invoicing module, reducing the need for separate small-business tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Available on web, iOS, and Android with consistent core functionality$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Interface feels less modern and polished than category leaders like Asana or Monday.com$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Smaller third-party integration ecosystem compared to larger competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Advanced automation and AI features lag behind platforms like ClickUp$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Some genuinely useful features, like the issue tracker and CRM, are locked behind the Business tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$File upload limits on lower tiers (10MB free, 25MB Pro) are restrictive for teams sharing large files$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Is Freedcamp really free?$q$, $q$Yes, Freedcamp's Free plan supports unlimited projects, tasks, storage, and users at no cost, though it has lower file upload limits and fewer advanced features than paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$How much does Freedcamp cost per user?$q$, $q$Paid plans start at $1.49 per user per month for Pro (billed annually), rising to $7.49 per user per month for Business and $16.99 per user per month for Enterprise, with higher rates for monthly billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Do I have to pay for external collaborators?$q$, $q$No, collaborators added to projects remain free even on paid Freedcamp plans, which is a notable difference from many per-seat competitors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Does Freedcamp include a CRM?$q$, $q$Yes, a built-in CRM is included starting on the Business tier, alongside an issue tracker, wiki, and invoicing module.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Who founded Freedcamp?$q$, $q$Freedcamp was founded in 2009-2010 in Santa Barbara, California, by Angel Grablev and Lofton Taylor.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Does Freedcamp have mobile apps?$q$, $q$Yes, Freedcamp offers native iOS and Android apps in addition to its web application.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Budget-conscious small business project management$q$, $q$Small businesses and startups use Freedcamp's free or low-cost paid tiers to manage projects and tasks without the per-seat costs of larger platforms.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Agency client collaboration$q$, $q$Agencies invite unlimited free external collaborators into client projects on paid plans without incurring extra per-seat charges.$q$, $q$Agencies and consultancies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Lightweight CRM and invoicing for small teams$q$, $q$Teams on the Business tier use the built-in CRM and Invoices+ module to manage client relationships and billing alongside project work.$q$, $q$Small business owners and freelancers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, NULL, $q$["Unlimited projects, tasks, storage, and users","Tasks, discussions, calendar, files, milestones, time tracking","10MB single file upload limit","Standard support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Pro$q$, $q$$1.49/user/month (annual) or $2.49/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Free","Email-in task creation","Google Drive, Dropbox, and OneDrive integration","25MB single file upload limit","Premium support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Business$q$, $q$$7.49/user/month (annual) or $8.99/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Pro","Project overview dashboard","Issue tracker and wiki","Built-in CRM and Invoices+","Project copy and custom reports","100MB single file upload limit","Advanced support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$Enterprise$q$, $q$$16.99/user/month (annual) or $19.99/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Business","White label branding","SSO with SAML","Daily data snapshots","Private cloud hosting","250MB single file upload limit","Under-1-business-day support response"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Freedcamp is a cloud-based project management and collaboration platform founded in 2009-2010 in Santa Barbara, California, by Angel Grablev and Lofton Taylor. It is best known for a permanently free tier supporting unlimited users, projects, and tasks.$q$, $q$The platform layers task management, milestones, file storage, an issue tracker, a wiki, a CRM, and invoicing across its tiers, positioning it as a lightweight operations hub for small businesses rather than just a to-do list.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include task lists with subtasks, milestones, a shared calendar, file storage, and team discussions, all available on the free plan for unlimited users.$q$, $q$Paid tiers add email-in task creation, cloud storage integrations, an issue tracker, a wiki, a built-in CRM, invoicing, custom reporting, white labeling, and SSO with SAML.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Freedcamp offers four tiers priced per user per month: Free ($0), Pro ($1.49 annually), Business ($7.49 annually), and Enterprise ($16.99 annually), with higher monthly-billing rates for each paid tier.$q$, $q$Collaborator-style guest users remain free even on paid plans, and file upload limits increase from 10MB on the free tier up to 250MB on Enterprise.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b5ae9c91-1ca9-4659-9b00-8decefc6bfbb', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Extension and trunk management$q$, $q$Point-and-click configuration of phone extensions and SIP trunk connections to telephony carriers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$IVR and call routing$q$, $q$Build interactive voice response menus, ring groups, hunt groups, and time-based call routing rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Call queues$q$, $q$Manage agent-based call queues with configurable hold music, overflow, and reporting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Voicemail and email delivery$q$, $q$Per-extension voicemail boxes with email delivery of voicemail messages as audio attachments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Conference bridges$q$, $q$Host multi-party conference calls directly through the PBX without third-party conferencing services.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Module marketplace$q$, $q$Extend functionality with free community modules or paid commercial modules for advanced features like recording and endpoint management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Endpoint Manager$q$, $q$Provision and manage Sangoma and third-party SIP desk phones centrally from the FreePBX interface.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Call detail records and reporting$q$, $q$Track and report on call volume, duration, and routing for auditing and capacity planning.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Core software is completely free and open source with no license fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Backed by Sangoma, a publicly traded company, giving it long-term development stability rare among open-source projects$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Powers over a million installations, meaning extensive community documentation, forums, and third-party expertise are available$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Can run on modest, inexpensive hardware for small deployments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Optional commercial modules and PBXact give a clear upgrade path to professional support without forcing it on free users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Requires Linux system administration knowledge to install, secure, and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Officially supported only on Debian Linux, limiting deployment flexibility for other distributions$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Some genuinely useful features, like advanced endpoint management, are gated behind paid commercial modules$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Telephony and VoIP configuration (SIP trunks, NAT traversal, codecs) has a steep learning curve for non-specialists$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$No official cloud-hosted SaaS version directly from the FreePBX project itself, requiring self-hosting or a third-party host$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Is FreePBX free to use?$q$, $q$Yes, the FreePBX core software is completely free and open source. Sangoma, the project's sponsor, monetizes optional commercial modules, hardware, and its fully supported PBXact product instead.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Who maintains FreePBX?$q$, $q$FreePBX has been developed and sponsored by Sangoma Technologies since it acquired Schmooze Com Inc. in January 2015. The project originally started in 2004 as AMP, built by Coalescent Systems.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$What operating system does FreePBX run on?$q$, $q$FreePBX is officially supported on Debian Linux, installed either via a bash installer script on an existing Debian system or through a pre-built ISO distribution.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$What is the difference between FreePBX and PBXact?$q$, $q$FreePBX is the free, self-managed open-source project, while PBXact is Sangoma's commercial, pre-bundled, professionally supported version of the same underlying software with a maintenance contract.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$What is the underlying telephony engine behind FreePBX?$q$, $q$FreePBX is a web-based management GUI built on top of Asterisk, the open-source telephony engine; the current release supports Asterisk versions 20 and 21.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$How many businesses use FreePBX?$q$, $q$FreePBX is reported to power more than one million phone system installations worldwide, making it one of the most widely deployed open-source PBX platforms.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Small business phone systems$q$, $q$IT administrators deploy self-hosted FreePBX servers to run a full-featured business phone system without per-user SaaS licensing fees.$q$, $q$Small and mid-sized business IT administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Managed service provider deployments$q$, $q$MSPs and telecom integrators deploy and support FreePBX or PBXact systems for multiple client businesses using Sangoma hardware and commercial modules.$q$, $q$Managed service providers and telecom integrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Home-lab and hobbyist telephony$q$, $q$Telecom hobbyists run FreePBX on inexpensive hardware to learn VoIP administration or manage a personal or small-office phone system.$q$, $q$Telecom hobbyists and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$FreePBX Core (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full PBX management GUI on top of Asterisk","Extension, trunk, and IVR configuration","Call queues, voicemail, and conferencing","Community modules and support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$Commercial Modules$q$, $q$Varies by module$q$, $q$One-time or subscription, per module$q$, NULL, $q$["Advanced endpoint management","Extended call recording and reporting","Additional integrations and premium modules"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$PBXact (Sangoma commercial)$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["Pre-bundled, professionally supported FreePBX distribution","Turnkey hardware appliance options","Maintenance and support contracts"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FreePBX is a free, open-source, web-based GUI for managing Asterisk-based phone systems. It originated in 2004 as AMP (Asterisk Management Portal) built by Coalescent Systems, and has been owned and sponsored since 2015 by Sangoma Technologies following its acquisition of Schmooze Com Inc.$q$, $q$It powers more than a million business phone system installations worldwide and remains free and open source at its core, with Sangoma generating revenue through optional commercial modules, hardware, and its fully supported PBXact product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FreePBX provides a point-and-click interface for managing extensions, SIP trunks, IVR menus, ring groups, call queues, voicemail, and conference bridges on top of the Asterisk telephony engine.$q$, $q$The current release, FreePBX 17, runs on PHP 8.2 with support for Asterisk 20 and 21, and is officially installed on Debian Linux via a bash installer or a pre-built ISO.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The FreePBX core software is completely free to download, install, and use, with no license fee for the base system.$q$, $q$Sangoma monetizes the ecosystem through optional commercial modules, SIP phones and PBX appliances, and PBXact, its fully supported commercial version of FreePBX, none of which are required to run a functional phone system.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2a33553b-3246-4484-92da-a333ec40b5e4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Shared inbox ticketing$q$, $q$Converts incoming support emails into tickets inside shared mailboxes that any assigned agent can respond to.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Unlimited agents and mailboxes$q$, $q$No built-in limits on the number of support agents, tickets, or mailboxes, unlike per-seat commercial help desks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Collision detection$q$, $q$Prevents two agents from replying to the same ticket at the same time, avoiding duplicate or conflicting responses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Mobile apps$q$, $q$Native iOS and Android apps let agents manage tickets from mobile devices.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$50-plus optional modules$q$, $q$A marketplace of paid modules adds live chat, knowledge base, CRM, Slack and WhatsApp integration, workflow automation, and more.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$API and webhooks$q$, $q$Programmatic access for building custom integrations and automations around the help desk.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Multi-language support$q$, $q$The interface supports more than 30 languages, along with accessibility features like screen reader support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Flexible self-hosting$q$, $q$Deployable via Docker, one-click installers on shared hosting through Softaculous, or manual PHP/MySQL installation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Core application is completely free with no per-agent or per-ticket licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$No artificial limits on agents, tickets, or mailboxes, unlike most commercial help desk SaaS tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Modular pricing lets teams pay only for the specific advanced features they actually need$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Lightweight PHP/MySQL stack that can run on inexpensive shared or VPS hosting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Full data ownership and control, appealing to privacy- and compliance-conscious organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Self-hosting requires ongoing server maintenance, security patching, and backup management$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Advanced functionality like live chat, CRM, and SSO requires purchasing separate paid modules$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Smaller ecosystem and community than large commercial help desks like Zendesk or Freshdesk$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$No official managed hosting from the FreeScout project itself; managed options come from third parties$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Interface and feature depth can feel less polished than heavily funded commercial competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Is FreeScout completely free?$q$, $q$The core FreeScout application is free and open source under AGPL-3.0 with no per-agent fees. Optional paid modules add advanced functionality like live chat, CRM, and SSO for an additional cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Why was FreeScout created?$q$, $q$FreeScout was created in 2018 after Help Scout discontinued its free plan and forced free accounts onto paid pricing, prompting the developer to build an open-source, self-hostable alternative.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Can I self-host FreeScout on shared hosting?$q$, $q$Yes, since FreeScout is a PHP and MySQL application built on Laravel, it can be deployed on many shared hosting plans, in addition to Docker and one-click cloud deployment options.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Does FreeScout limit the number of support agents?$q$, $q$No, FreeScout has no built-in limits on the number of agents, tickets, or mailboxes, unlike most per-seat commercial help desk platforms.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Does FreeScout have mobile apps?$q$, $q$Yes, native iOS and Android apps are available for managing tickets from mobile devices.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$How is FreeScout different from Zendesk or Help Scout?$q$, $q$FreeScout is free, open source, and self-hosted, giving teams full data control and no per-agent fees, whereas Zendesk and Help Scout are commercial cloud SaaS products billed per agent per month.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Cost-conscious support teams$q$, $q$Growing support teams migrate from per-agent SaaS help desks to FreeScout to eliminate recurring per-seat costs as they add more agents.$q$, $q$Small and mid-sized business support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Privacy and data-residency focused support$q$, $q$Organizations with strict data control or compliance requirements self-host FreeScout to keep customer support data entirely on their own infrastructure.$q$, $q$Privacy- and compliance-focused organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Agency and multi-client support desks$q$, $q$Agencies use FreeScout's unlimited mailboxes and modules to run shared support inboxes for multiple client brands from one self-hosted instance.$q$, $q$Agencies and managed service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Free Core (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited agents, tickets, and mailboxes","Shared inbox ticketing and collision detection","Mobile apps for iOS and Android","30-plus language support","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Optional Paid Modules$q$, $q$Varies by module$q$, $q$One-time or subscription, per module$q$, NULL, $q$["Live chat","Knowledge base","Slack, WhatsApp, and Telegram integration","Built-in CRM","Workflow automation and SAML SSO"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$Third-Party Managed Hosting$q$, $q$From approximately $9/month$q$, $q$Monthly$q$, NULL, $q$["Hosting and server maintenance handled by a third-party provider","No DevOps required","Not an official FreeScout product"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FreeScout is a free, open-source, self-hosted help desk and shared mailbox application built with PHP and Laravel. It launched in 2018 as a direct response to Help Scout discontinuing its free plan, positioning itself as a permanently free alternative teams could run on their own infrastructure.$q$, $q$The core product replicates the shared-inbox, conversational-ticketing experience of commercial tools like Help Scout and Zendesk, with unlimited agents, tickets, and mailboxes at no license cost.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FreeScout converts incoming support emails into tickets inside shared mailboxes, with agent assignment, collision detection, canned responses, and mailbox merging or moving.$q$, $q$A marketplace of more than 50 optional paid modules adds live chat, a knowledge base, Slack and WhatsApp integration, a built-in CRM, workflow automation, and SSO, letting teams pay only for the advanced features they need.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core FreeScout application is completely free to self-host under the AGPL-3.0 license, with no per-agent or per-ticket fees.$q$, $q$Optional paid modules unlock advanced features individually, and third-party providers offer managed FreeScout hosting for teams without DevOps resources, commonly starting around $9 per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
