INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4008e96-5007-46e7-98c7-0f90f45c63fa', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$SIP telephony engine$q$, $q$Full support for Session Initiation Protocol (SIP) call signaling and media handling for building VoIP systems.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$WebRTC support$q$, $q$Native support for SIP over WebSocket and WebRTC, enabling browser-based real-time voice and video communication.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Video transcoding and conferencing$q$, $q$Multipoint Control Unit (MCU) style video conferencing and video transcoding between different codecs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Cross-platform, commodity hardware support$q$, $q$Runs on hardware ranging from a Raspberry Pi to multi-core enterprise servers without requiring proprietary telecom equipment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Modular architecture$q$, $q$A module-based system (mod_sofia, mod_conference, and others) lets developers extend or customize call handling and media processing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Carrier-grade scalability$q$, $q$Designed to handle large volumes of concurrent calls, making it suitable for carrier and platform-scale deployments, not just small PBX systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Scripting and API integration$q$, $q$Supports embedded scripting languages and APIs (including Event Socket) for programmatic call control and integration with external systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$SignalWire cloud connectivity$q$, $q$The mod_signalwire module simplifies connecting a self-hosted FreeSWITCH instance to SignalWire's cloud communications platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Completely free and open source with no license fees for self-hosted use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Battle-tested, carrier-grade architecture used underneath many commercial VoIP and contact center platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Strong native WebRTC and video support, ahead of many competing telephony engines historically$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Backed by a well-resourced commercial steward, SignalWire, founded by the project's original creators$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Runs on a wide range of hardware, from low-cost single-board computers to large multi-core servers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$No built-in administrative GUI, dashboard, or provisioning system out of the box$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Requires significant telecom and systems engineering expertise to deploy into a production-ready system$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Steeper learning curve than GUI-based alternatives like FreePBX for basic PBX-style use cases$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$No official free managed hosting; commercial support and cloud options are priced on request$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Documentation and community resources, while substantial, can be less beginner-friendly than more polished commercial platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Is FreeSWITCH free to use?$q$, $q$Yes, FreeSWITCH is free and open source under the Mozilla Public License 1.1, with no license fee to download, self-host, or modify it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Who created FreeSWITCH?$q$, $q$FreeSWITCH was created by Anthony Minessale II, Brian West, and Michael Jerris, first announced in January 2006 and released in May 2008.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$What is the relationship between FreeSWITCH and SignalWire?$q$, $q$SignalWire is a commercial company founded in 2017-2018 by Anthony Minessale and the core FreeSWITCH team to serve as the project's permanent commercial steward. FreeSWITCH remains an independent open-source project rather than SignalWire's proprietary software.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Does FreeSWITCH come with a management interface?$q$, $q$No, FreeSWITCH is a bare telephony engine with no built-in administrative dashboard, provisioning system, or billing tools; building a full system requires additional engineering or third-party tooling.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$How is FreeSWITCH different from FreePBX?$q$, $q$FreeSWITCH is a low-level telephony engine, while FreePBX is a web-based administrative GUI built on top of a different engine, Asterisk. FreeSWITCH requires more engineering work to turn into a usable phone system but offers more flexibility for custom or high-scale deployments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$What license is FreeSWITCH released under?$q$, $q$FreeSWITCH is released under the Mozilla Public License (MPL) version 1.1, a permissive open-source license that allows both open-source and commercial use.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Carrier-grade communications platforms$q$, $q$Telecom companies and platform builders use FreeSWITCH as the media-handling and call-control core of large-scale voice and video communications products.$q$, $q$Telecom carriers and communications platform builders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$WebRTC application backends$q$, $q$Developers use FreeSWITCH's native WebRTC support to power browser-based voice and video calling features inside web and mobile applications.$q$, $q$Software developers building real-time communication features$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Custom PBX and contact center systems$q$, $q$Systems integrators build bespoke PBX and contact center solutions on top of FreeSWITCH when they need more flexibility than a GUI-based platform like FreePBX provides.$q$, $q$VoIP integrators and IT consultancies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$Open Source Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MPL 1.1","SIP, WebRTC, and video communications engine","Self-hosted on any supported hardware","Community documentation and forums"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$FreeSWITCH Advantage (SignalWire)$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["Premium support directly from FreeSWITCH's original creators","Priority issue resolution","Guidance for production deployment and scaling"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$SignalWire Cloud Platform$q$, $q$Usage-based, contact for pricing$q$, $q$Pay-as-you-go$q$, NULL, $q$["Managed, elastic FreeSWITCH-based cloud infrastructure","Voice, video, messaging, and AI voice agent APIs","No self-hosting or telecom infrastructure required"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FreeSWITCH is a free, open-source, software-defined telephony platform created by Anthony Minessale II, Brian West, and Michael Jerris, first announced in January 2006 and released in May 2008. It provides the core engine for building SIP, WebRTC, voice, and video communications systems.$q$, $q$In 2017-2018, the original FreeSWITCH team founded SignalWire, a commercial company based in Palo Alto, California, to serve as the project's permanent commercial steward while FreeSWITCH itself remains an independent open-source project under the Mozilla Public License 1.1.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FreeSWITCH supports SIP telephony, WebRTC for browser-based real-time communication, video transcoding, and multipoint video conferencing (MCU) functionality, and can run on hardware ranging from a Raspberry Pi to multi-core servers.$q$, $q$It functions as a low-level telephony engine rather than a finished product, providing no administrative GUI, billing, or provisioning tools out of the box, which distinguishes it from GUI-layered platforms like FreePBX.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FreeSWITCH is free to download and use under its open-source MPL 1.1 license, with no license fee for self-hosted deployment.$q$, $q$SignalWire offers commercial options including a premium 'FreeSWITCH Advantage' support plan and a broader usage-based cloud communications platform for organizations that want managed support or hosted infrastructure, both priced on request.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('359edbcb-cdb7-4e0e-96ec-f81303289aa2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
